#include<bits/stdc++.h>
using namespace std;
int n,a[101],dp[101][101],root[101][101];
void print(int l,int r)
{
    if(l==r)
    {
        printf("%d ",l);
        return;
    }
    if(l>r)
    {
        return;
    }
    printf("%d ",root[l][r]);
    print(l,root[l][r]-1);
    print(root[l][r]+1,r);
}
int dfs(int l,int r)
{
    if(l==r)
    {
        return a[l];
    }
    if(l>r)
    {
        return 1;
    }
    if(dp[l][r])
    {
        return dp[l][r];
    }
    dp[l][r]=0;
    for(int i=l;i<=r;i++)
    {
        int tmp=a[i]+dfs(l,i-1)*dfs(i+1,r);
        if(tmp>dp[l][r])
        {
            dp[l][r]=tmp;
            root[l][r]=i;
        }
    }
    return dp[l][r];
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    printf("%d\n",dfs(1,n));
    print(1,n);
    return 0;
}
